#### 7.3 Redis 캐시 전략

```kotlin
@Service
class FollowCacheService(
    private val redisTemplate: RedisTemplate<String, Any>,
    private val followService: FollowService,
) {
    companion object {
        const val FOLLOWER_COUNT_KEY = "follow:count:followers:%s"
        const val FOLLOWING_COUNT_KEY = "follow:count:followings:%s"
        const val FOLLOWERS_LIST_KEY = "follow:list:followers:%s:%d:%d"
        const val CACHE_TTL = 3600L  // 1시간
    }

    fun getFollowerCount(userId: String): Long {
        val key = FOLLOWER_COUNT_KEY.format(userId)
        return redisTemplate.opsForValue().get(key) as? Long
            ?: followService.countFollowers(userId, 0).also { count ->
                redisTemplate.opsForValue().set(key, count, CACHE_TTL, TimeUnit.SECONDS)
            }
    }

    fun invalidateFollowerCount(userId: String) {
        redisTemplate.delete(FOLLOWER_COUNT_KEY.format(userId))
    }
}
```

**캐시 무효화 시점**:
- `follow()` 실행 시: `invalidateFollowerCount(followingId)`
- `unfollow()` 실행 시: `invalidateFollowerCount(followingId)`

