@Controller
class FollowController(
    private val followService: FollowService,
) {
    @QueryMapping
    fun followers(
        @UserId userId: String,
        @Argument limit: Int?,
        @Argument offset: Int?,
        env: DataFetchingEnvironment,
    ): List<FollowResponse> {
        val dataLoader = env.getDataLoader<String, UserDTO>("user")
        val follows = followService.getFollowers(userId, limit ?: 20, offset ?: 0)

        return follows.map { follow ->
            FollowResponse(
                id = follow.id,
                followerId = follow.followerId,
                followingId = follow.followingId,
                follower = dataLoader.load(follow.followerId),  // 배치로 로드
                createdAt = follow.createdAt.toString()
            )
        }
    }
}
